import{_ as i,o as r,c as l,j as a,a6 as t,em as s,ir as h}from"./chunks/framework.UYVGz2W_.js";const k=JSON.parse('{"title":"Kitsu ドキュメント","description":"","frontmatter":{},"headers":[],"relativePath":"ja/index.md","filePath":"ja/index.md"}'),o={name:"ja/index.md"},n=s+"#logo-kitsu",u=h+"#logo-cgwire";function c(f,e,d,p,m,b){return r(),l("div",null,[...e[0]||(e[0]=[a("p",null,[a("img",{src:n,alt:"Kitsu Banner"})],-1),t('<h1 id="kitsu-ドキュメント" tabindex="-1">Kitsu ドキュメント <a class="header-anchor" href="#kitsu-ドキュメント" aria-label="Permalink to “Kitsu ドキュメント”">​</a></h1><p><a href="https://cg-wire.com/kitsu" target="_blank" rel="noreferrer">Kitsu</a> は、アニメーションおよび VFX 制作のためのコラボレーションプラットフォームです。 そのクリーンな UI と共有データベースを通じて、アーティスト、制作マネージャー、スーパーバイザー、ベンダー、クライアントなど、制作プロセスに関わるすべての関係者を結びつけます。</p><h3 id="kitsuの紹介" tabindex="-1">Kitsuの紹介 <a class="header-anchor" href="#kitsuの紹介" aria-label="Permalink to “Kitsuの紹介”">​</a></h3><p>制作を成功させるために必要なKitsuの基本的なコンセプトを理解するためのリンクをいくつかご紹介します。</p><ul><li><a href="./configure-kitsu/">Getting Started With Kitsu</a>: Kitsuで使用される主な原則と一般的な用語を学び、制作ワークフローをよりよく計画しましょう。</li><li><a href="./team/">Preparing Your Team</a>: チームメンバーを準備し、各メンバーの部署と権限を定義します。</li></ul><h3 id="制作物の作成" tabindex="-1">制作物の作成 <a class="header-anchor" href="#制作物の作成" aria-label="Permalink to “制作物の作成”">​</a></h3><p>以下では、作成を検討している制作物の種類に合わせたガイドをご覧いただけます。</p><ul><li><a href="./tvshow/">テレビ番組制作物の作成</a> アセット、ショット、シーケンス、エピソード、編集を使用してテレビ番組制作物を作成します</li><li><a href="./feature/">長編映画制作物の作成</a> アセット、ショット、シーケンス、編集を使用して長編映画制作物（約1,000エンティティ）を作成します。</li><li><a href="./short/">ショート制作の作成</a>: ショート制作（約500のアセットとショット）を、アセット、ショット、シーケンス、編集で作成します。</li><li><a href="./short-shot/">ショットのみの制作の作成</a> ショート制作（約500ショット）を、ショット、シーケンス、編集のみで作成します</li><li><a href="./short-asset/">アセットのみの制作を作成する</a> アセットのみを使用した短い制作（約500アセット）を作成します。</li><li><a href="./videogame/">ビデオゲーム制作を作成する</a> アセット、マップ、レベル、チャプター（テレビ番組として）を使用したビデオゲーム制作を作成します。</li><li><a href="./nft/">NFTコレクションを作成する</a> アセットとNFTコレクションを使用したNFTコレクションを作成します。</li></ul><h3 id="メタカラム、フィルター、制作設定" tabindex="-1">メタカラム、フィルター、制作設定 <a class="header-anchor" href="#メタカラム、フィルター、制作設定" aria-label="Permalink to “メタカラム、フィルター、制作設定”">​</a></h3><ul><li><a href="./meta-column/">メタカラム</a>: 制作物のメタデータの作成と整理方法について学びます。</li><li><a href="./filter/">フィルター</a>: 強力な検索機能で重要な情報に絞り込みます</li><li><a href="./configure-prod/">制作固有のワークフロー設定</a>: さまざまな強力な設定で、特定の制作物を好みに合わせて微調整します。</li></ul><h3 id="割り当て、見積もり、スケジュール" tabindex="-1">割り当て、見積もり、スケジュール <a class="header-anchor" href="#割り当て、見積もり、スケジュール" aria-label="Permalink to “割り当て、見積もり、スケジュール”">​</a></h3><p>このセクションでは、Kitsuの主な使用例をいくつかご紹介します。</p><ul><li><a href="./assignation/">タスクの割り当て</a>: チームに誰かを追加し、タスクを割り当てる方法を学びます。</li><li><a href="./estimation/">見積もり &amp; チームのノルマ</a>: タスクの完了までに必要な日数（入札）を計算する方法と、チームの効率性を確認する方法を学びます。</li><li><a href="./schedules/">スケジュール</a>: スタジオレベルからタスクレベルまで、Kitsuのさまざまなスケジュール機能を確認できます。</li></ul><h3 id="ステータス、公開、サムネイル" tabindex="-1">ステータス、公開、サムネイル <a class="header-anchor" href="#ステータス、公開、サムネイル" aria-label="Permalink to “ステータス、公開、サムネイル”">​</a></h3><p>作業を整理し、チームにその進捗状況を通知する方法</p><ul><li><a href="./status/">ステータスとフィードバック</a>: ステータスの変更方法と、作業の進捗状況をチームに知らせる方法。</li><li><a href="./publish/">公開</a>: 作業を公開し、チームと共有する方法。</li><li><a href="./thumbnails/">サムネイル</a>: アセットとショットにサムネイルを適用する方法。</li></ul><h3 id="社内レビューとクライアントのプレイリスト" tabindex="-1">社内レビューとクライアントのプレイリスト <a class="header-anchor" href="#社内レビューとクライアントのプレイリスト" aria-label="Permalink to “社内レビューとクライアントのプレイリスト”">​</a></h3><p>社内および社外レビューの整理方法：</p><ul><li><a href="./review/">レビュー</a>: タスクに関するすべてのフィードバックを確認する方法を学びましょう。</li><li><a href="./review-weekly/">デイリーおよびウィークリーレビュー</a>: ビデオ版を素早く収集し、レビューに集中しましょう。</li><li><a href="./playlist-client/">クライアント用プレイリスト</a>: 管理された環境でクライアントと作業を収集し、共有しましょう。</li></ul><h3 id="スーパーバイザーのワークフロー" tabindex="-1">スーパーバイザーのワークフロー <a class="header-anchor" href="#スーパーバイザーのワークフロー" aria-label="Permalink to “スーパーバイザーのワークフロー”">​</a></h3><p>スーパーバイザーの場合、Kitsu を使用する際のユースケースは制作チームの場合とは異なる場合があります。</p><ul><li><a href="./supervisor-team/">部署の管理</a>: チームを効果的に管理し監督する方法を発見します。</li><li><a href="./supervisor-tasks/">タスクの監督</a>: タスクの割り当てを常に把握する方法を学びます。</li></ul><h3 id="プロデューサーのワークフロー" tabindex="-1">プロデューサーのワークフロー <a class="header-anchor" href="#プロデューサーのワークフロー" aria-label="Permalink to “プロデューサーのワークフロー”">​</a></h3><p>プロデューサーとして、詳細から全体像へと視点を移す能力を習得することは不可欠です。</p><ul><li><a href="./production-report/">制作レポートの作成</a>: 制作レポートを作成するために必要なすべてを学びましょう。</li><li><a href="./studio-report/">スタジオレポートの作成</a>: スタジオの制作で常に一歩先を行くために。</li></ul><h3 id="開発者のワークフロー" tabindex="-1">開発者のワークフロー <a class="header-anchor" href="#開発者のワークフロー" aria-label="Permalink to “開発者のワークフロー”">​</a></h3><p>開発者の方は、スタジオのパイプライン内でKitsuを拡張および統合するための可能性について、いくつかご確認ください。</p><ul><li><a href="./custom-actions/">カスタムアクション</a>: カスタムアクションは、現在のKitsuの選択からカスタムエンドに情報を送信するシンプルなHTTPリクエストです。</li><li><a href="./bots/">Bots</a>: 主な用途は、gazu（KitsuのPythonクライアント）を使用したスクリプト作成、および当社のAPIを使用できるその他の用途です。</li><li><a href="./publisher/">Kitsu Publisher</a>: 制作の進捗状況を共有し、配信を検証するために使用するウェブアプリケーションです。</li><li><a href="./chat-integration/">チャット統合</a>: Discord、Slack、Mattermostなどの人気メッセージングアプリに直接Kitsuの通知を受け取ることができます。</li><li><a href="./installation/">オープンソースセットアップ</a>: スタジオ環境内でローカルバージョンのKitsuをセルフデプロイする方法について学びます。</li></ul><h3 id="チュートリアル" tabindex="-1">チュートリアル <a class="header-anchor" href="#チュートリアル" aria-label="Permalink to “チュートリアル”">​</a></h3><p>Kitsuの重要な機能に焦点を当てた、YouTubeの包括的なビデオチュートリアルにアクセスできます。下記リンクをクリックしてご覧ください。</p><p><a href="https://www.youtube.com/playlist?list=PLp_1gB5ZBHXqnQgZ4TCrAt7smxesaDo29" target="_blank" rel="noreferrer">Kitsuチュートリアルチャンネル</a></p><h3 id="著者について" tabindex="-1">著者について <a class="header-anchor" href="#著者について" aria-label="Permalink to “著者について”">​</a></h3><p>Kitsuは、フランスに拠点を置くCG Wire社によって開発されました。当社は、アニメーションスタジオの制作管理と効率的なパイプライン構築を支援しています。</p><p>可能な限り、ソフトウェア職人の原則に従っています。当社のコーディングに対する情熱は、堅牢な品質の提供と優れた開発者体験の提供に対する当社の取り組みに反映されています。当社の幅広い専門知識を活用し、スタジオが制作の複雑性を克服し、より効率的なコラボレーション、より迅速な納品を実現し、より優れた画像の制作を支援しています。</p><p>詳細については、<a href="https://cg-wire.com" target="_blank" rel="noreferrer">cg-wire.com</a>をご覧ください。</p>',35),a("p",null,[a("a",{href:"https://cg-wire.com",target:"_blank",rel:"noreferrer"},[a("img",{src:u,alt:"CG Wire ロゴ"})])],-1)])])}const g=i(o,[["render",c]]);export{k as __pageData,g as default};
